-- ---------------------------------------------------------------------------
-- UI rendering helpers
-- ---------------------------------------------------------------------------
-- Pure-UI helpers: ImGui draw code, style-stack push/pop pairs, and
-- composite widgets (hero band, session strip, footer rail, v5 rows,
-- card container). Called from both the Render.* screens in this file
-- and from Render.main_window's chat body.


-- Render the floating toast. Anchor rect (x, y, w, h) is the screen-space
-- bounds of whatever the toast should sit at the bottom of -- in practice,
-- the main ReaAssist window. Called from the main render loop so the toast
-- persists across page navigation while it's still alive.
function UI.render_float_toast(anchor_x, anchor_y, anchor_w, anchor_h)
  local tip = S.float_toast
  if not tip then return end
  local now = reaper.time_precise()
  local alpha
  if now < tip.fade_in_end_at then
    alpha = (now - tip.start_at) / tip.fade_in_s
  elseif tip.sticky then
    alpha = 1.0  -- sticky: hold at full alpha until replaced or cleared
  elseif now < tip.hold_end_at then
    alpha = 1.0
  elseif now < tip.fade_out_end_at then
    alpha = 1 - (now - tip.hold_end_at) / tip.fade_out_s
  else
    S.float_toast = nil
    return
  end
  if alpha < 0 then alpha = 0 elseif alpha > 1 then alpha = 1 end

  -- Scale the alpha byte of a u32 colour so the bubble fades uniformly.
  local function _scale_alpha(col, a)
    return (col & 0xFFFFFF00) | math_floor((col & 0xFF) * a + 0.5)
  end

  local bottom_margin = RA.SC(36)
  local target_x = anchor_x + anchor_w * 0.5
  local target_y = anchor_y + anchor_h - bottom_margin

  ImGui.ImGui_SetNextWindowPos(RA.ctx, target_x, target_y,
    ImGui.ImGui_Cond_Always(), 0.5, 1.0)
  ImGui.ImGui_SetNextWindowBgAlpha(RA.ctx, alpha)

  local flags = ImGui.ImGui_WindowFlags_NoDecoration()
              | ImGui.ImGui_WindowFlags_NoInputs()
              | ImGui.ImGui_WindowFlags_NoMove()
              | ImGui.ImGui_WindowFlags_AlwaysAutoResize()
              | ImGui.ImGui_WindowFlags_NoSavedSettings()
              | ImGui.ImGui_WindowFlags_NoFocusOnAppearing()
              | ImGui.ImGui_WindowFlags_NoNav()

  PushStyleColor(RA.ctx, ImGui.ImGui_Col_WindowBg(),
    _scale_alpha(TK.card, 1.0))
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Border(),
    _scale_alpha(TK.border, alpha))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowPadding(), RA.SC(14), RA.SC(9))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowRounding(), RA.SC(10))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowBorderSize(), 1)
  if ImGui.ImGui_Begin(RA.ctx, "##reaassist_float_toast", nil, flags) then
    local accent_col = (tip.kind == "err") and TK.red or TK.green
    PushFont(RA.ctx, FONT.inter_semi, RA.SC(12))
    PushStyleColor(RA.ctx, ImGui.ImGui_Col_Text(), _scale_alpha(accent_col, alpha))
    Text(RA.ctx, tip.text)
    PopStyleColor(RA.ctx)
    PopFont(RA.ctx)
  end
  ImGui.ImGui_End(RA.ctx)
  ImGui.ImGui_PopStyleVar(RA.ctx, 3)
  PopStyleColor(RA.ctx, 2)
end

-- Keep every visual run surface consistent when a requested safety backup
-- fails. Execution has already been stopped by the caller; this helper makes
-- that stop visible and gives the user a deliberate recovery path.
function UI.report_backup_run_blocked(err)
  local message = UI.t("code.backup_failed_run", {
    error = tostring(err or "unknown_error"),
  }, "Safety backup failed (" .. tostring(err or "unknown_error")
    .. "). The generated code was NOT run. Check the project folder, disk "
    .. "space, and permissions, then try again. To proceed without a backup, "
    .. "turn off Auto-backup in Settings and run the code again.")
  Log.add_error(message)
  S.status = "error"
  if UI.show_float_toast then
    UI.show_float_toast(message, "err")
  end
  return message
end


-- Draw a unified highlight border around the whole window when a file
-- is being dragged over any drop target. Called once per frame at the end.
function UI.draw_drop_overlay()
  if not S.drop_active then return end
  local draw = ImGui.ImGui_GetWindowDrawList(RA.ctx)
  local wx, wy = ImGui.ImGui_GetWindowPos(RA.ctx)
  local ww, wh = ImGui.ImGui_GetWindowSize(RA.ctx)
  -- Filled tint over the whole window.
  ImGui.ImGui_DrawList_AddRectFilled(draw, wx, wy, wx + ww, wy + wh, 0xFFFF0018)
  -- Yellow border.
  ImGui.ImGui_DrawList_AddRect(draw, wx + 1, wy + 1, wx + ww - 1, wy + wh - 1, 0xFFFF00AA, 0, 0, 2)
  S.drop_active = false
end

-- =============================================================================
-- Styled tooltip: shows a tooltip with dark theme colors when the previous
-- item is hovered. Call immediately after the widget.
-- V5 tooltip: 500ms hover delay, 300ms fade-in on first show, 300ms fade-out
-- when hover leaves. Keeps a single active-tip entry in S._tip so both timers
-- survive across frames. Call `UI.tooltip_v5(text)` immediately after the
-- widget whose hover should trigger it, then call `UI.tooltip_render_v5()`
-- once per frame AFTER every possible tooltip_v5 call -- typically near the
-- end of the main loop so the tooltip paints above all other windows.
UI.TIP_DELAY_S  = 0.5
UI.TIP_FADE_S   = 0.3
function UI.tooltip_v5(text)
  -- AllowWhenDisabled so disabled items (e.g. paid-only models for free-tier
  -- users) still fire their tooltip -- they're often the most important
  -- items to explain, since users want to know WHY they can't click them.
  if ImGui.ImGui_IsItemHovered(RA.ctx,
       ImGui.ImGui_HoveredFlags_AllowWhenDisabled()) then
    local now = time_precise()
    -- If we're hovering a NEW item (different text) OR the previous entry was
    -- already fading out, start fresh -- this prevents a mid-fade tooltip
    -- from being "revived" with its old alpha and a stale anchor.
    if not S._tip or S._tip.text ~= text or S._tip.fade_start then
      local mx, my = ImGui.ImGui_GetMousePos(RA.ctx)
      S._tip = {
        text        = text,
        hover_start = now,
        fade_start  = nil,
        anchor_x    = mx + RA.SC(14),
        anchor_y    = my + RA.SC(18),
      }
    else
      -- Track cursor while still hovering so the tooltip follows the mouse.
      local mx, my = ImGui.ImGui_GetMousePos(RA.ctx)
      S._tip.anchor_x = mx + RA.SC(14)
      S._tip.anchor_y = my + RA.SC(18)
    end
    S._tip_hovered_this_frame = true
  end
end

function UI.tooltip_render_v5()
  local tip = S._tip
  if not tip then
    S._tip_hovered_this_frame = false
    return
  end
  local now = time_precise()
  local alpha
  if S._tip_hovered_this_frame then
    -- Hover continues: alpha = fade-in curve past the delay window.
    local t = now - tip.hover_start
    if t < UI.TIP_DELAY_S then
      alpha = 0
    else
      alpha = math_min(1.0, (t - UI.TIP_DELAY_S) / UI.TIP_FADE_S)
    end
  else
    -- Not hovered this frame: start (or continue) fade-out.
    tip.fade_start = tip.fade_start or now
    local t = now - tip.fade_start
    alpha = 1.0 - t / UI.TIP_FADE_S
    if alpha <= 0 then
      S._tip = nil
      S._tip_hovered_this_frame = false
      return
    end
  end
  if alpha > 0 then
    ImGui.ImGui_SetNextWindowPos(RA.ctx, tip.anchor_x, tip.anchor_y)
    ImGui.ImGui_SetNextWindowBgAlpha(RA.ctx, alpha)
    PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_Alpha(),              alpha)
    -- Match global tooltip styling (UI.tooltip above): SC(11)/SC(9)
    -- inner padding, SC(5) rounded corners, 1px border.
    PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowPadding(),      RA.SC(11), RA.SC(9))
    PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowRounding(),     RA.SC(5))
    PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowBorderSize(),   1)
    PushStyleColor(RA.ctx, ImGui.ImGui_Col_WindowBg(), TK.card)
    PushStyleColor(RA.ctx, ImGui.ImGui_Col_Border(),   TK.border_str)
    PushStyleColor(RA.ctx, ImGui.ImGui_Col_Text(),     TK.text)
    local flags = ImGui.ImGui_WindowFlags_NoDecoration()
                | ImGui.ImGui_WindowFlags_NoInputs()
                | ImGui.ImGui_WindowFlags_NoMove()
                | ImGui.ImGui_WindowFlags_AlwaysAutoResize()
                | ImGui.ImGui_WindowFlags_NoSavedSettings()
                | ImGui.ImGui_WindowFlags_NoFocusOnAppearing()
                | ImGui.ImGui_WindowFlags_NoNav()
    local visible = ImGui.ImGui_Begin(RA.ctx, "##v5_tooltip", nil, flags)
    if visible then
      PushFont(RA.ctx, FONT.inter_reg, RA.SC(12))
      -- Global max width: wrap at SC(500); AlwaysAutoResize then
      -- shrinks the window to the wrapped content width.
      ImGui.ImGui_PushTextWrapPos(RA.ctx, RA.SC(500))
      Text(RA.ctx, tip.text)
      ImGui.ImGui_PopTextWrapPos(RA.ctx)
      PopFont(RA.ctx)
    end
    ImGui.ImGui_End(RA.ctx)
    PopStyleColor(RA.ctx, 3)
    ImGui.ImGui_PopStyleVar(RA.ctx, 4)
  end
  S._tip_hovered_this_frame = false
end

function UI.tooltip(text)
  UI.tooltip_v5(text)
end

-- Draw a subtle focus ring around the last widget if it is active (focused).
-- Uses the draw list to overlay a 1px accent-tinted rectangle so it works
-- regardless of ImGui's built-in border styling.
function UI.focus_ring()
  if ImGui.ImGui_IsItemActive(RA.ctx) then
    local x1, y1 = ImGui.ImGui_GetItemRectMin(RA.ctx)
    local x2, y2 = ImGui.ImGui_GetItemRectMax(RA.ctx)
    local dl = ImGui.ImGui_GetWindowDrawList(RA.ctx)
    ImGui.ImGui_DrawList_AddRect(dl, x1, y1, x2, y2, COL.ASSIST, 0, 0, 1.5)
  end
end

-- =============================================================================
-- Right-click context menu for text input fields
-- =============================================================================
-- ImGui's InputText widgets do not ship with a Copy/Paste/Cut popup on
-- right-click. macOS users in particular expect this on every text
-- field (and, over RDP, Cmd+V can be flaky depending on the remote
-- desktop client). Without it there is no obvious way to paste an
-- API key on a fresh install.
--
-- Pattern: call UI.input_with_menu IMMEDIATELY after any
-- ImGui_InputText / ImGui_InputTextWithHint / ImGui_InputTextMultiline
-- call, passing the (changed, new_value) tuple it returned and a stable
-- popup id derived from that input's own label. The helper attaches a
-- right-click popup to that just-rendered item and returns a possibly-
-- augmented tuple: if the user picks Paste, it returns (true,
-- clipboard_text); if Cut, (true, ""); otherwise unchanged.
--
-- Paste replaces the entire field rather than inserting at the cursor.
-- Cursor-aware paste would require an InputText edit-callback to
-- splice the clipboard into the live buffer, which is a much larger
-- change. The native Cmd+V / Ctrl+V paths still work for cursor-aware
-- paste; the right-click menu is the no-keyboard fallback for cases
-- (API keys, custom URLs, names) where the user pastes into an empty
-- or about-to-be-replaced field anyway.
function UI.input_with_menu(ctx, changed, new_value, popup_id)
  -- Hover/open detection still uses the last submitted InputText item, while
  -- popup_id owns the menu identity. Missing ids disable the menu rather than
  -- falling back to ImGui's implicit item id, which can assert on id==0.
  if popup_id == nil or popup_id == "" then
    return changed, new_value
  end
  if ImGui.ImGui_BeginPopupContextItem(ctx, popup_id) then
    if ImGui.ImGui_MenuItem(ctx, UI.t("common.copy", nil, "Copy")) then
      ImGui.ImGui_SetClipboardText(ctx, new_value or "")
    end
    if ImGui.ImGui_MenuItem(ctx, UI.t("common.paste", nil, "Paste")) then
      new_value = ImGui.ImGui_GetClipboardText(ctx) or ""
      changed   = true
    end
    if ImGui.ImGui_MenuItem(ctx, UI.t("common.cut", nil, "Cut")) then
      ImGui.ImGui_SetClipboardText(ctx, new_value or "")
      new_value = ""
      changed   = true
    end
    ImGui.ImGui_EndPopup(ctx)
  end
  return changed, new_value
end

-- =============================================================================
-- Shared settings-screen UI helpers
-- =============================================================================
-- The five settings-family screens (api_key, advanced, custom_llm,
-- preferred_plugins, fx_cache) all share the same visual language: 5 px
-- FramePadding, 4 px FrameRounding/GrabRounding/PopupRounding, secondary-
-- button palette, 1 px border, centered 20 px page title with an ice-blue
-- accent underline, and -- where applicable -- uppercase letter-spaced
-- section headers with a fading divider. Centralising these below means
-- edits to the visual language propagate to every screen at once.

-- Push the standard settings-screen style stack. Pair with pop_settings_styles.
function UI.push_settings_styles()
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Button(),        COL.BTN)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonHovered(), COL.BTN_HOV)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonActive(),  COL.BTN_ACT)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Border(),        COL.BORDER)
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FrameBorderSize(), 1)
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FramePadding(),    5, 5)
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FrameRounding(),   RA.SC(4))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_GrabRounding(),    RA.SC(4))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_PopupRounding(),   RA.SC(4))
end

function UI.pop_settings_styles()
  ImGui.ImGui_PopStyleVar(RA.ctx, 5)    -- FrameBorderSize, FramePadding, FrameRounding, GrabRounding, PopupRounding
  PopStyleColor(RA.ctx, 4)  -- Button, ButtonHovered, ButtonActive, Border
end

-- V5 modal dialog chrome.
--
-- One helper drives every BeginPopupModal in the script: factory reset,
-- clear-cache, key-error, unsaved-settings, advisory, risky-code, etc.
--
-- Visual language (matches Settings / card palette):
--   * PopupBg: blend between TK.card and TK.bg (~35% toward bg). Pure
--     TK.card is blinding white in light mode; a subtle tint softens
--     the modal while keeping it clearly lifted above the page. The
--     blend is theme-aware via UI.lerp_u32.
--   * Title bar = same blended tone (flush). The default ImGui title
--     strip (lighter band above the body) creates visual noise for
--     dialogs that are already small; blending the title bar into the
--     body lets the title read as a centered heading instead of a
--     chrome element. WindowTitleAlign = (0.5, 0.5) centers the title.
--   * Border = TK.border_str (muted grey), not accent -- the modal is
--     a surface, not an action.
--   * Default Button palette is the V5 "secondary" look (card_hover
--     fill, border frame). Primary / destructive buttons opt in via
--     UI.push_modal_primary_btn / UI.push_modal_danger_btn so call
--     sites only push one helper instead of 4 raw style colors.
--   * WindowPadding / FramePadding / rounding tuned to match the
--     Settings pinned bar and the capability-card chrome.
-- Pair with pop_modal_style.
function UI.push_modal_style()
  -- Softened modal surface: TK.card blended 35% toward TK.bg so the
  -- dialog reads as an elevated surface without the pure-white harshness
  -- of TK.card in light mode. Theme-aware via the lerp.
  local modal_bg = UI.lerp_u32(TK.card, TK.bg, 0.35)
  -- PopupBg is used by BeginPopupModal; WindowBg is used by standalone
  -- ImGui.ImGui_Begin dialogs (Update Available, File integrity). We push
  -- both so the same helper works for either container type.
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_PopupBg(),          modal_bg)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_WindowBg(),         modal_bg)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Text(),             TK.text)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_TextDisabled(),     TK.text_muted)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Border(),           TK.border_str)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_TitleBg(),          modal_bg)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_TitleBgActive(),    modal_bg)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_TitleBgCollapsed(), modal_bg)
  -- Secondary button palette (V5 default): card_hover fill with a
  -- gentle accent tint on hover / active. Keeps Cancel / Skip / Back
  -- buttons reading as neutral surfaces, reserving saturated fills
  -- for primary / danger actions.
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Button(),           TK.card_hover)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonHovered(),
    UI.lerp_u32(TK.card_hover, TK.accent_ui, 0.35))
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonActive(),
    UI.lerp_u32(TK.card_hover, TK.accent_ui, 0.55))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FrameBorderSize(),  1)
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowPadding(),    RA.SC(18), RA.SC(16))
  -- FramePadding tuned to match the V5 Settings pinned bar (compact
  -- vertical, not chunky). SC(12, 5) gives ~24px tall buttons at 100%
  -- DPI, leaving room for title bar + body + button row in popups as
  -- short as SC(130) without clipping.
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FramePadding(),     RA.SC(12), RA.SC(5))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FrameRounding(),    RA.SC(5))
  -- BeginPopupModal honours WindowRounding; push PopupRounding too as
  -- cheap insurance in case a future ImGui version flips the rule.
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowRounding(),   RA.SC(7))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_PopupRounding(),    RA.SC(7))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowTitleAlign(), 0.5, 0.5)
end

function UI.pop_modal_style()
  ImGui.ImGui_PopStyleVar(RA.ctx, 7)   -- FrameBorderSize, WindowPadding, FramePadding, FrameRounding, WindowRounding, PopupRounding, WindowTitleAlign
  PopStyleColor(RA.ctx, 11)            -- PopupBg, WindowBg, Text, TextDisabled, Border, TitleBg, TitleBgActive, TitleBgCollapsed, Button, ButtonHovered, ButtonActive
end

-- Primary modal button (Save / Confirm / Add / OK / Run): accent fill
-- with white text. Four colour pushes paired with pop_modal_primary_btn.
-- Replaces the 4-push-4-pop SEND_BTN boilerplate at every modal call site.
function UI.push_modal_primary_btn()
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Button(),        TK.accent)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonHovered(),
    UI.lerp_u32(TK.accent, 0xFFFFFFFF, 0.12))
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonActive(),
    UI.lerp_u32(TK.accent, 0x000000FF, 0.15))
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Text(),          TK.accent_text)
end
function UI.pop_modal_primary_btn() PopStyleColor(RA.ctx, 4) end

function UI.update_dialog_center_cursor(inner_w, item_w)
  local pad_x = ImGui.ImGui_GetStyleVar(RA.ctx,
    ImGui.ImGui_StyleVar_WindowPadding())
  SetCursorPosX(RA.ctx, pad_x + math_max((inner_w - item_w) * 0.5, 0))
end

function UI.brand_font(key)
  local base = OptionalFonts and OptionalFonts._base_fonts
  if not base and OptionalFonts and OptionalFonts._remember_base_fonts then
    OptionalFonts._remember_base_fonts()
    base = OptionalFonts._base_fonts
  end
  return (base and base[key]) or (FONT and FONT[key])
end

function UI.brand_metric_key(size)
  local light = UI.brand_font("inter_light")
  local bold = UI.brand_font("inter_bold")
  return tostring(size) .. ":" .. tostring(light) .. ":" .. tostring(bold)
end

function UI.update_dialog_wordmark(inner_w)
  local size = RA.SC(22)
  local pad_x = ImGui.ImGui_GetStyleVar(RA.ctx,
    ImGui.ImGui_StyleVar_WindowPadding())
  local f_reg = UI.brand_font("inter_reg") or FONT.inter_reg
  local f_bold = UI.brand_font("inter_bold") or FONT.inter_bold
  PushFont(RA.ctx, f_reg, size)
  local rea_w = CalcTextSize(RA.ctx, "Rea")
  PopFont(RA.ctx)
  PushFont(RA.ctx, f_bold, size)
  local assist_w = CalcTextSize(RA.ctx, "Assist")
  PopFont(RA.ctx)

  UI.update_dialog_center_cursor(inner_w, rea_w + assist_w)
  local x, y = ImGui.ImGui_GetCursorScreenPos(RA.ctx)
  local dl = ImGui.ImGui_GetWindowDrawList(RA.ctx)
  ImGui.ImGui_DrawList_AddTextEx(dl, f_reg, size, x, y,
    UI.lerp_u32(0x000000FF, TK.accent, 0.72), "Rea")
  ImGui.ImGui_DrawList_AddTextEx(dl, f_bold, size, x + rea_w, y,
    TK.accent, "Assist")
  SetCursorPosX(RA.ctx, pad_x)
  Dummy(RA.ctx, inner_w, math_floor(size * 1.25))
end

function UI.update_dialog_text_center(text, inner_w, color, font, size)
  text = tostring(text or "")
  if text == "" then return end
  if size then PushFont(RA.ctx, font, size) elseif font then PushFont(RA.ctx, font) end
  local text_w = CalcTextSize(RA.ctx, text)
  UI.update_dialog_center_cursor(inner_w, text_w)
  if color then
    ImGui.ImGui_TextColored(RA.ctx, color, text)
  else
    Text(RA.ctx, text)
  end
  if size or font then PopFont(RA.ctx) end
end

function UI.update_dialog_text_center_wrapped(text, inner_w, color, font, size, max_w)
  text = tostring(text or "")
  if text == "" then return end
  if size then PushFont(RA.ctx, font, size) elseif font then PushFont(RA.ctx, font) end
  local text_w = CalcTextSize(RA.ctx, text)
  local limit_w = math_min(max_w or inner_w, inner_w - RA.SC(24))
  if text_w <= limit_w then
    UI.update_dialog_center_cursor(inner_w, text_w)
    if color then
      ImGui.ImGui_TextColored(RA.ctx, color, text)
    else
      Text(RA.ctx, text)
    end
  else
    local font_sz = size or ImGui.ImGui_GetFontSize(RA.ctx)
    local max_units = math_max(16, math_floor(limit_w / math_max(font_sz * 0.52, 1)))
    for _, line in ipairs(UI._split_wrap_units(text, max_units)) do
      local line_w = CalcTextSize(RA.ctx, line)
      UI.update_dialog_center_cursor(inner_w, line_w)
      if color then
        ImGui.ImGui_TextColored(RA.ctx, color, line)
      else
        Text(RA.ctx, line)
      end
    end
  end
  if size or font then PopFont(RA.ctx) end
end

-- Discrete update progress, mirroring the bootstrap installer's square
-- activity row. Keep a minimum number of cells so one-file updates do not
-- collapse into a single progress bar.
function UI.update_dialog_progress_cells(total, done, active)
  total = math_max(0, total or 0)
  done  = math_max(0, math_min(done or 0, total))
  local cells = (total > 0) and math_max(total, 12) or (active and 12 or 0)
  local cell_h  = RA.SC(10)
  local gap     = RA.SC(4)
  local cx, cy  = ImGui.ImGui_GetCursorScreenPos(RA.ctx)
  local avail_w = ImGui.ImGui_GetContentRegionAvail(RA.ctx)
  if cells > 0 then
    local cell_w  = math_min(cell_h, math_max(RA.SC(4),
      math_floor((avail_w - (cells - 1) * gap) / cells)))
    local total_w = cells * cell_w + (cells - 1) * gap
    local start_x = cx + math_floor((avail_w - total_w) * 0.5)
    local dl      = ImGui.ImGui_GetWindowDrawList(RA.ctx)
    local lit = (total > 0) and math_floor((done / total) * cells + 0.0001) or 0
    if done >= total and total > 0 then lit = cells end
    local active_i = nil
    if active and lit < cells then
      local span = cells - lit
      active_i = lit + (math_floor(time_precise() * 8) % span) + 1
    end
    for i = 1, cells do
      local x = start_x + (i - 1) * (cell_w + gap)
      local fill = (i <= lit or i == active_i) and TK.accent or TK.card_hover
      ImGui.ImGui_DrawList_AddRectFilled(dl, x, cy, x + cell_w, cy + cell_h,
        fill, RA.SC(2))
    end
  end
  Dummy(RA.ctx, avail_w, cell_h)
end

-- =============================================================================
-- Language fonts and width-aware wrapping
-- =============================================================================
-- Chat text can mix Latin, CJK, Hangul, and kana. These helpers choose optional
-- language fonts when needed and count wide codepoints as two wrap units so
-- manual wrapping matches what the user actually sees.
function UI.active_chat_font()
  if OptionalFonts and OptionalFonts.active_font then
    return OptionalFonts.active_font() or FONT.inter_reg
  end
  return FONT.inter_reg
end

function UI.active_chat_font_key()
  if OptionalFonts and OptionalFonts.active_font_key then
    return OptionalFonts.active_font_key() or "inter"
  end
  return "inter"
end

function UI.text_needs_language_font(text)
  local ok, needed = pcall(function()
    for _, cp in utf8.codes(tostring(text or "")) do
      if UI._codepoint_wrap_units(cp) == 2 then return true end
    end
    return false
  end)
  return ok and needed or false
end

function UI.cjk_fallback_font()
  if not (OptionalFonts and OptionalFonts.entry_for_language_idx) then
    return nil
  end
  local seen = {}
  local function try_idx(idx)
    local key = tostring(idx or "")
    if key == "" or seen[key] then return nil end
    seen[key] = true
    local entry = type(idx) == "string"
      and OptionalFonts.entry_for_language_code
      and OptionalFonts.entry_for_language_code(idx)
      or OptionalFonts.entry_for_language_idx(idx)
    if entry then
      if entry.font then return entry.font end
      if OptionalFonts.load_available_entry then
        local ok = OptionalFonts.load_available_entry(entry)
        if ok and entry.font then return entry.font end
      elseif OptionalFonts.file_exists and OptionalFonts.file_exists(entry) then
        local ok = OptionalFonts.load_entry and OptionalFonts.load_entry(entry)
        if ok and entry.font then return entry.font end
      end
    end
    return nil
  end
  local font = try_idx(prefs and prefs.reply_language_idx)
  if font then return font end
  if OptionalFonts.ordered_entry_indices then
    for _, idx in ipairs(OptionalFonts.ordered_entry_indices()) do
      font = try_idx(idx)
      if font then return font end
    end
  else
    for idx in pairs(OptionalFonts.entries or {}) do
      font = try_idx(idx)
      if font then return font end
    end
  end
  return nil
end

function UI.cjk_font_for_text(text)
  if not (OptionalFonts and OptionalFonts.entry_for_language_idx) then
    return nil
  end
  text = tostring(text or "")
  local wants_hangul, wants_kana, wants_han = false, false, false
  local ok = pcall(function()
    for _, cp in utf8.codes(text) do
      if (cp >= 0xAC00 and cp <= 0xD7AF)
          or (cp >= 0x1100 and cp <= 0x11FF) then
        wants_hangul = true
      elseif (cp >= 0x3040 and cp <= 0x30FF)
          or (cp >= 0x31F0 and cp <= 0x31FF) then
        wants_kana = true
      elseif (cp >= 0x3400 and cp <= 0x9FFF)
          or (cp >= 0xF900 and cp <= 0xFAFF)
          or (cp >= 0x20000 and cp <= 0x3FFFD) then
        wants_han = true
      end
    end
  end)
  if not ok then return UI.cjk_fallback_font() end

  local order
  if wants_hangul then
    order = { "ko", "ja", "zh-Hans", "zh-Hant" }
  elseif wants_kana then
    order = { "ja", "zh-Hans", "zh-Hant", "ko" }
  elseif wants_han then
    local cur_code = prefs and prefs.language_code
    if (not cur_code or cur_code == "") and CFG
        and CFG.language_code_for_legacy_idx then
      cur_code = CFG.language_code_for_legacy_idx(
        prefs and prefs.reply_language_idx or 0)
    end
    if cur_code == "zh-Hant" then
      order = { "zh-Hant", "zh-Hans", "ja", "ko" }
    else
      order = { "zh-Hans", "zh-Hant", "ja", "ko" }
    end
  else
    return nil
  end

  for _, code in ipairs(order) do
    local entry = OptionalFonts.entry_for_language_code
      and OptionalFonts.entry_for_language_code(code)
    if entry then
      if entry.font then return entry.font end
      if OptionalFonts.load_available_entry then
        local loaded = OptionalFonts.load_available_entry(entry)
        if loaded and entry.font then return entry.font end
      elseif OptionalFonts.file_exists and OptionalFonts.file_exists(entry) then
        local loaded = OptionalFonts.load_entry and OptionalFonts.load_entry(entry)
        if loaded and entry.font then return entry.font end
      end
    end
  end
  return UI.cjk_fallback_font()
end

function UI.font_for_language_text(text)
  if UI.text_needs_language_font(text) then
    return UI.cjk_font_for_text(text) or UI.cjk_fallback_font()
  end
  return nil
end

function UI.chat_units_per_line(avail_w)
  local avg_unit_w = ImGui.ImGui_GetFontSize(RA.ctx) * 0.48
  return math_floor(math_max(avail_w / avg_unit_w, 20))
end

function UI._codepoint_wrap_units(cp)
  if (cp >= 0x1100 and cp <= 0x11FF)
      or (cp >= 0x2E80 and cp <= 0xA4CF)
      or (cp >= 0xAC00 and cp <= 0xD7AF)
      or (cp >= 0xF900 and cp <= 0xFAFF)
      or (cp >= 0xFE10 and cp <= 0xFE6F)
      or (cp >= 0xFF01 and cp <= 0xFF60)
      or (cp >= 0xFFE0 and cp <= 0xFFE6)
      or (cp >= 0x20000 and cp <= 0x3FFFD) then
    return 2
  end
  return 1
end

function UI._text_wrap_units(text)
  text = tostring(text or "")
  local ok, units = pcall(function()
    local total = 0
    for _, cp in utf8.codes(text) do
      total = total + UI._codepoint_wrap_units(cp)
    end
    return total
  end)
  return ok and units or #text
end

function UI._take_wrap_units(text, max_units)
  text = tostring(text or "")
  max_units = math_max(1, tonumber(max_units) or 1)
  local ok, head, tail, used = pcall(function()
    local cut, total = 0, 0
    for pos, cp in utf8.codes(text) do
      local u = UI._codepoint_wrap_units(cp)
      if total > 0 and total + u > max_units then break end
      local next_pos = utf8.offset(text, 2, pos)
      cut = next_pos and (next_pos - 1) or #text
      total = total + u
      if total >= max_units then break end
    end
    if cut <= 0 and #text > 0 then cut = 1; total = 1 end
    return str_sub(text, 1, cut), str_sub(text, cut + 1), total
  end)
  if ok then return head, tail, used end
  return str_sub(text, 1, max_units), str_sub(text, max_units + 1), max_units
end

function UI._split_wrap_units(text, max_units)
  local chunks, rest = {}, tostring(text or "")
  while rest ~= "" do
    local head, tail = UI._take_wrap_units(rest, max_units)
    if head == "" then
      head, tail = str_sub(rest, 1, 1), str_sub(rest, 2)
    end
    chunks[#chunks + 1] = head
    rest = tail
  end
  return chunks
end

function UI.unwrap_wrapped_selection(original, wrapped, a, b)
  original = tostring(original or "")
  wrapped = tostring(wrapped or "")
  a = math_max(0, math_min(tonumber(a) or 0, #wrapped))
  b = math_max(a, math_min(tonumber(b) or #wrapped, #wrapped))
  local result = {}
  local wi, oi = 1, 1
  while wi <= #wrapped and wi <= b do
    local wc = str_sub(wrapped, wi, wi)
    local oc = oi <= #original and str_sub(original, oi, oi) or ""
    local emit = wi > a
    if wc == oc then
      if emit then result[#result + 1] = wc end
      wi = wi + 1
      oi = oi + 1
    elseif wc == "\n" and oc == " " then
      if emit then result[#result + 1] = " " end
      wi = wi + 1
      oi = oi + 1
    elseif wc == "\n" then
      -- Hard wrap inserted inside a long word; omit the artificial break and
      -- do not advance original text so the next glyph rejoins the word.
      wi = wi + 1
    else
      if emit then result[#result + 1] = wc end
      wi = wi + 1
      oi = oi + 1
    end
  end
  return tbl_concat(result)
end

function UI.expire_missing_scroll_to_msg()
  if not S.scroll_to_msg then return false end
  S.scroll_to_msg_frames = (S.scroll_to_msg_frames or 0) + 1
  if S.scroll_to_msg_frames > 30 then
    S.scroll_to_msg = nil
    S.scroll_to_msg_frames = nil
    return true
  end
  return false
end

function UI._utf8_safe_prefix_bytes(text, max_bytes)
  text = tostring(text or "")
  max_bytes = math_floor(tonumber(max_bytes) or 0)
  if max_bytes <= 0 then return "", text end
  if #text <= max_bytes then return text, "" end

  local function is_continuation(b)
    return b and b >= 0x80 and b <= 0xBF
  end
  local function lead_len(b)
    if not b then return 0 end
    if b < 0x80 then return 1 end
    if b >= 0xC2 and b <= 0xDF then return 2 end
    if b >= 0xE0 and b <= 0xEF then return 3 end
    if b >= 0xF0 and b <= 0xF4 then return 4 end
    return 0
  end

  local start = max_bytes
  while start > 0 and is_continuation(text:byte(start)) do
    start = start - 1
  end
  local cut = 0
  if start > 0 then
    local need = lead_len(text:byte(start))
    if need > 0 and start + need - 1 <= max_bytes then
      cut = max_bytes
    else
      cut = start - 1
    end
  end
  return str_sub(text, 1, cut), str_sub(text, cut + 1)
end

function UI._utf8_prefix_chars(text, max_chars)
  text = tostring(text or "")
  max_chars = math_floor(tonumber(max_chars) or 0)
  if max_chars <= 0 then return "" end
  local len = utf8.len(text)
  if len and len <= max_chars then return text end
  if len then
    local cut = utf8.offset(text, max_chars + 1)
    return cut and str_sub(text, 1, cut - 1) or text
  end
  return UI._utf8_safe_prefix_bytes(text, max_chars)
end

function UI._utf8_truncate_chars(text, max_chars, ellipsis)
  text = tostring(text or "")
  max_chars = math_floor(tonumber(max_chars) or 0)
  if max_chars <= 0 then return "" end
  local len = utf8.len(text)
  if len and len <= max_chars then return text end
  ellipsis = ellipsis or "..."
  local ell_len = utf8.len(ellipsis) or #ellipsis
  local keep = math_max(max_chars - ell_len, 0)
  return UI._utf8_prefix_chars(text, keep) .. ellipsis
end

function UI._utf8_drop_last_char(text)
  text = tostring(text or "")
  local len = utf8.len(text)
  if len and len > 0 then return UI._utf8_prefix_chars(text, len - 1) end
  return str_sub(text, 1, math_max(#text - 1, 0))
end

function UI._utf8_char_count(text)
  text = tostring(text or "")
  return utf8.len(text) or #text
end

function UI.preview_cache_key(...)
  local parts = { ... }
  for i = 1, #parts do
    parts[i] = tostring(parts[i] or "")
  end
  return tbl_concat(parts, "\31")
end

function UI.preview_flags_key(flags)
  if type(flags) ~= "table" then return "" end
  local keys = {}
  for k in pairs(flags) do keys[#keys + 1] = tostring(k) end
  table.sort(keys)
  local parts = {}
  for i = 1, #keys do
    local k = keys[i]
    parts[i] = k .. "=" .. tostring(flags[k])
  end
  return tbl_concat(parts, "\31")
end

function UI.preview_text_lines(text)
  text = tostring(text or "")
  local lines, rp = {}, 1
  while rp <= #text do
    local nl = str_find(text, "\n", rp, true)
    lines[#lines + 1] = nl and str_sub(text, rp, nl - 1) or str_sub(text, rp)
    if not nl then break end
    rp = nl + 1
  end
  return lines
end

function UI.preview_payload_cache(cache, key, build_fn)
  if cache and cache.key == key then return cache end
  local text = build_fn and build_fn() or ""
  text = tostring(text or "")
  return {
    key = key,
    text = text,
    lines = UI.preview_text_lines(text),
  }
end

function UI.preview_display_lines(cache, wrap_w)
  if type(cache) ~= "table" then return {} end
  local sample_w = 0
  if ImGui.ImGui_CalcTextSize then
    sample_w = ImGui.ImGui_CalcTextSize(RA.ctx, "M")
  end
  if not sample_w or sample_w <= 0 then
    sample_w = math_max(ImGui.ImGui_GetFontSize(RA.ctx) * 0.60, 1)
  end
  local wrap_units = math_floor(math_max((tonumber(wrap_w) or 0) / sample_w, 20))
  if cache.display_units == wrap_units and cache.display_lines then
    return cache.display_lines
  end

  local display = {}
  for i = 1, #(cache.lines or {}) do
    local line = cache.lines[i] or ""
    if line == "" then
      display[#display + 1] = ""
    else
      local chunks = UI._split_wrap_units(line, wrap_units)
      for j = 1, #chunks do
        display[#display + 1] = chunks[j]
      end
    end
  end
  cache.display_units = wrap_units
  cache.display_lines = display
  return display
end

function UI.render_preview_display_lines(lines)
  if type(lines) ~= "table" or #lines == 0 then return end

  local function draw_line(line)
    Text(RA.ctx, line ~= "" and line or " ")
  end

  if type(ImGui.ImGui_CreateListClipper) == "function"
      and type(ImGui.ImGui_ListClipper_Begin) == "function"
      and type(ImGui.ImGui_ListClipper_Step) == "function"
      and type(ImGui.ImGui_ListClipper_GetDisplayRange) == "function"
      and type(ImGui.ImGui_ListClipper_End) == "function" then
    UI._preview_line_clipper = UI._preview_line_clipper
      or ImGui.ImGui_CreateListClipper(RA.ctx)
    if UI._preview_line_clipper then
      if not UI._preview_line_clipper_attached
          and type(ImGui.ImGui_Attach) == "function" then
        ImGui.ImGui_Attach(RA.ctx, UI._preview_line_clipper)
        UI._preview_line_clipper_attached = true
      end
      ImGui.ImGui_ListClipper_Begin(UI._preview_line_clipper, #lines)
      while ImGui.ImGui_ListClipper_Step(UI._preview_line_clipper) do
        local display_start, display_end =
          ImGui.ImGui_ListClipper_GetDisplayRange(UI._preview_line_clipper)
        for i = display_start + 1, math_min(display_end, #lines) do
          draw_line(lines[i])
        end
      end
      ImGui.ImGui_ListClipper_End(UI._preview_line_clipper)
      return
    end
  end

  for i = 1, #lines do draw_line(lines[i]) end
end

function UI.chat_message_value_cull_sig(v, depth)
  local tv = type(v)
  if tv ~= "table" then return tv .. ":" .. tostring(v) end
  depth = (depth or 0) + 1
  if depth > 3 then return "table" end

  local keys = {}
  for k in pairs(v) do keys[#keys + 1] = k end
  table.sort(keys, function(a, b)
    local ta, tb = type(a), type(b)
    if ta ~= tb then return ta < tb end
    return tostring(a) < tostring(b)
  end)

  local parts = {}
  for i = 1, #keys do
    local k = keys[i]
    local item = v[k]
    local item_sig
    if type(item) == "table" then
      item_sig = UI.chat_message_value_cull_sig(item, depth)
    elseif type(item) == "function"
        or type(item) == "userdata"
        or type(item) == "thread" then
      item_sig = type(item)
    else
      item_sig = type(item) .. ":" .. tostring(item)
    end
    parts[#parts + 1] = tostring(k) .. "=" .. item_sig
  end
  return "{" .. tbl_concat(parts, "\30") .. "}"
end

function UI.chat_message_static_cull_sig(msg)
  if type(msg) ~= "table" then return "" end
  local generated = msg.generated_code and msg.generated_code.content or ""
  local attach_names = msg.attach_names
  local attach_sig = ""
  if type(attach_names) == "table" and #attach_names > 0 then
    attach_sig = tbl_concat(attach_names, "\30")
  end
  local typed = msg.typed_actions
  local typed_results = typed and typed.action_results or nil
  local typed_sig = ""
  if typed then
    typed_sig = UI.preview_cache_key(
      typed.present,
      typed.valid,
      typed.executed,
      typed.deferred_pending,
      typed.kind,
      typed.error,
      UI.chat_message_value_cull_sig(typed_results))
  end
  local lua_artifact_sig = UI.chat_message_value_cull_sig(msg.lua_artifact)
  local ceiling_sig = UI.chat_message_value_cull_sig(msg.ceiling_inject_info)
  local recovery_attach_sig =
    UI.chat_message_value_cull_sig(msg.recovery_attachments)

  if msg._chat_cull_sig_content ~= msg.content
      or msg._chat_cull_sig_code ~= msg.code_block
      or msg._chat_cull_sig_generated ~= generated
      or msg._chat_cull_sig_attach ~= attach_sig
      or msg._chat_cull_sig_typed ~= typed_sig
      or msg._chat_cull_sig_lua_artifact ~= lua_artifact_sig
      or msg._chat_cull_sig_ceiling ~= ceiling_sig
      or msg._chat_cull_sig_recovery_attach ~= recovery_attach_sig
      or msg._chat_cull_sig_storage ~= msg.storage_note then
    msg._chat_cull_sig_content = msg.content
    msg._chat_cull_sig_code = msg.code_block
    msg._chat_cull_sig_generated = generated
    msg._chat_cull_sig_attach = attach_sig
    msg._chat_cull_sig_typed = typed_sig
    msg._chat_cull_sig_lua_artifact = lua_artifact_sig
    msg._chat_cull_sig_ceiling = ceiling_sig
    msg._chat_cull_sig_recovery_attach = recovery_attach_sig
    msg._chat_cull_sig_storage = msg.storage_note
    msg._chat_cull_static_sig = UI.preview_cache_key(
      msg.role,
      msg.content,
      msg.code_type,
      msg.code_block,
      generated,
      attach_sig,
      typed_sig,
      lua_artifact_sig,
      ceiling_sig,
      recovery_attach_sig,
      msg.storage_note)
  end
  return msg._chat_cull_static_sig or ""
end

function UI.chat_message_cull_key(msg, i, count, avail_w, chat_font_key,
                                  running_cost, running_cost_count, prev_msg)
  msg = msg or {}
  local active_provider_label = ""
  if msg.local_answer and msg.local_retry_available ~= false
      and PROVIDERS and PROVIDERS.active then
    local active_provider = PROVIDERS.active()
    active_provider_label = active_provider
      and tostring(active_provider.label or active_provider.id or "")
      or ""
  end
  return UI.preview_cache_key(
    math_floor(tonumber(avail_w) or 0),
    prefs.show_details and "details" or "no_details",
    prefs.chat_font_idx,
    prefs.ui_scale_idx,
    prefs.language_code,
    prefs.reply_language_idx,
    prefs.provider_idx,
    prefs.model_idx,
    prefs.thinking_idx,
    chat_font_key,
    Diag and Diag.uploader_enabled and "diag_on" or "diag_off",
    S.status,
    S.pending_display_idx == i,
    i == count,
    i == count and S.pending_code and "pending_code" or "",
    running_cost,
    running_cost_count,
    prev_msg and prev_msg.from_card,
    msg.ctx_label,
    msg.model_label,
    msg.provider_id,
    msg.model_id,
    msg.tok_in,
    msg.tok_out,
    msg.cost,
    msg.free_tier,
    msg.response_time,
    msg.tok_cache_read,
    msg.tok_cache_create,
    msg.thinking_label,
    msg.fx_cache_label,
    msg.api_calls,
    msg.model_calls,
    msg.transport_retries,
    msg.auto_ran,
    msg.auto_run_block_reason,
    msg.run_status,
    msg.run_blocked,
    msg.edit_mode,
    msg.truncated,
    msg.local_answer,
    msg.local_retry_available,
    msg.local_llm_requested,
    msg.llm_retry_prompt,
    active_provider_label,
    msg.link_label,
    msg.link_url,
    msg.typed_action_token_cap,
    msg.typed_action_lua_requested,
    msg.typed_action_undo_clicked,
    msg.screen_reader_undo_clicked,
    msg.recovery,
    msg.recovery_used,
    msg.recovery_prompt,
    msg.fallback_provider_id,
    msg.fallback_model_id,
    msg.fallback_label,
    msg.jsfx_saved_path,
    msg.jsfx_saved_fx_name,
    msg.jsfx_added_to_tracks,
    msg.jsfx_status,
    msg.jsfx_auto_saved,
    msg.ceiling_injected,
    msg.from_card,
    UI.chat_message_static_cull_sig(msg))
end

function UI.maybe_prompt_missing_active_language_font()
  if not (OptionalFonts and api_keys) then return end
  if api_keys.pending_reply_language_idx then return end
  local idx = prefs and prefs.reply_language_idx
  local entry = OptionalFonts.entry_for_language_idx
    and OptionalFonts.entry_for_language_idx(idx)
  if not entry then return end
  if OptionalFonts.is_ready_for_language_idx
      and OptionalFonts.is_ready_for_language_idx(idx) then return end
  if api_keys.missing_reply_language_font_idx == idx then return end
  api_keys.missing_reply_language_font_idx = idx
  api_keys.pending_reply_language_idx = idx
  api_keys.font_prompt_force_english = true
  prefs.reply_language_idx = 1
  prefs.language_code = "en"
  if S.wrap_cache then S.wrap_cache = {} end
  api_keys.open_font_download_confirm = true
end

function UI.render_font_download_popup()
  if not (OptionalFonts and api_keys) then return end
  local function font_t(key, values, fallback)
    if api_keys.font_prompt_force_english then return fallback end
    return UI.t(key, values, fallback)
  end
  local popup_id = font_t("settings.font.title", nil,
    "Download Language Font") .. "##font_download"
  if api_keys.open_font_download_confirm then
    ImGui.ImGui_OpenPopup(RA.ctx, popup_id)
    api_keys.open_font_download_confirm = nil
  end
  local idx = api_keys.pending_reply_language_idx
  local entry = OptionalFonts.entry_for_language_idx
    and OptionalFonts.entry_for_language_idx(idx)
  if not entry then return end

  local d = OptionalFonts.download or {}
  local same_download = (d.entry and d.entry.key == entry.key) and true or false
  local busy = (same_download and OptionalFonts.is_busy()) and true or false
  local failed = (same_download and d.state == "failed") and true or false
  local body_text = font_t("settings.font.body", {
    language = entry.label,
    size = entry.size_label,
  }, entry.label .. " needs a " .. entry.size_label
    .. " font download so chat text renders correctly.")
  local error_text = (failed and (d.last_error or font_t("settings.font.failed", nil,
      "Font download failed.")))
    or api_keys.font_download_error
  local function wrapped_line_count(text, font_sz, max_w)
    text = tostring(text or "")
    if text == "" then return 0 end
    local limit_w = math_max(1, max_w or RA.SC(360))
    local max_units = math_max(16,
      math_floor(limit_w / math_max((font_sz or RA.SC(13)) * 0.52, 1)))
    return #(UI._split_wrap_units(text, max_units))
  end
  local text_lines = busy and 2 or wrapped_line_count(body_text,
    RA.SC(13), RA.SC(360))
  if not busy and error_text then
    text_lines = text_lines + 1 + wrapped_line_count(error_text,
      RA.SC(12), RA.SC(360))
    if failed and OptionalFonts.diagnostic_text then
      text_lines = text_lines + 2
    end
  end
  local pop_w = RA.SC(430)
  local pop_h = math_max(RA.SC(250),
    RA.SC(206) + math_max(0, text_lines - 1) * RA.SC(18))
  if update and update._main_x and update._main_w then
    ImGui.ImGui_SetNextWindowPos(RA.ctx,
      update._main_x + (update._main_w - pop_w) * 0.5,
      update._main_y + (update._main_h - pop_h) * 0.5,
      ImGui.ImGui_Cond_Appearing())
  end
  ImGui.ImGui_SetNextWindowSize(RA.ctx, pop_w, pop_h,
    ImGui.ImGui_Cond_Appearing())
  UI.push_modal_style()
  if ImGui.ImGui_BeginPopupModal(RA.ctx, popup_id, true,
      ImGui.ImGui_WindowFlags_NoResize()) then
    local cw = ImGui.ImGui_GetContentRegionAvail(RA.ctx)

    if OptionalFonts.is_ready_for_language_idx(idx) then
      prefs.reply_language_idx = idx
      prefs.language_code = CFG.language_code_for_legacy_idx
        and CFG.language_code_for_legacy_idx(idx) or prefs.language_code
      api_keys.pending_reply_language_idx = nil
      api_keys.font_download_error = nil
      api_keys.missing_reply_language_font_idx = nil
      api_keys.font_prompt_force_english = nil
      OptionalFonts.download = { state = "idle" }
      if S.wrap_cache then S.wrap_cache = {} end
      if UI.show_float_toast then
        local toast_key = entry.font_source == "system"
          and "settings.font.system_fallback_toast"
          or "settings.font.ready_toast"
        local toast_fallback = entry.font_source == "system"
          and ("Using a system font for " .. entry.label)
          or (entry.label .. " font installed")
        UI.show_float_toast(font_t(toast_key, {
          language = entry.label,
        }, toast_fallback), "ok")
      end
      ImGui.ImGui_CloseCurrentPopup(RA.ctx)
      ImGui.ImGui_EndPopup(RA.ctx)
      UI.pop_modal_style()
      return
    end

    UI.update_dialog_wordmark(cw)
    ImGui.ImGui_Spacing(RA.ctx)
    UI.update_dialog_text_center(
      busy and (d.status_text or font_t("settings.font.downloading", nil,
        "Downloading font..."))
        or font_t("settings.font.heading", nil, "Download Language Font?"),
      cw, TK.text, nil, RA.SC(16))
    ImGui.ImGui_Spacing(RA.ctx)

    if busy then
      local done = d.done or 0
      UI.update_dialog_progress_cells(1, done, true)
      ImGui.ImGui_Spacing(RA.ctx)
      UI.update_dialog_text_center(entry.filename, cw, TK.text_muted,
        FONT.mono_reg, RA.SC(10))
    else
      UI.update_dialog_text_center_wrapped(
        body_text,
        cw, TK.text, nil, RA.SC(13), cw - RA.SC(36))
      if error_text then
        ImGui.ImGui_Spacing(RA.ctx)
        UI.update_dialog_text_center_wrapped(
          error_text,
          cw, TK.red, nil, RA.SC(12), cw - RA.SC(36))
        if failed and OptionalFonts.diagnostic_text then
          ImGui.ImGui_Spacing(RA.ctx)
          local copy_label = font_t("settings.font.copy_details", nil,
            "Copy details")
          local copy_w = math_max(RA.SC(96),
            CalcTextSize(RA.ctx, copy_label) + RA.SC(22))
          SetCursorPosX(RA.ctx,
            GetCursorPosX(RA.ctx) + math_floor((cw - copy_w) * 0.5))
          if ImGui.ImGui_Button(RA.ctx,
              copy_label .. "##font_download_details", copy_w, 0) then
            ImGui.ImGui_SetClipboardText(RA.ctx,
              OptionalFonts.diagnostic_text(d))
            if UI.show_float_toast then
              UI.show_float_toast(font_t("settings.font.details_copied", nil,
                "Font download details copied."), "ok")
            end
          end
        end
      end
    end

    ImGui.ImGui_Spacing(RA.ctx)
    local cancel_w, dl_w, gap = RA.SC(82), RA.SC(132), RA.SC(12)
    local row_w = cancel_w + gap + dl_w
    SetCursorPosX(RA.ctx, GetCursorPosX(RA.ctx) + math_floor((cw - row_w) * 0.5))
    ImGui.ImGui_BeginDisabled(RA.ctx, busy)
    if ImGui.ImGui_Button(RA.ctx,
        font_t("common.cancel", nil, "Cancel") .. "##font_cancel",
        cancel_w, 0) then
      api_keys.pending_reply_language_idx = nil
      api_keys.font_download_error = nil
      api_keys.missing_reply_language_font_idx = idx
      api_keys.font_prompt_force_english = nil
      ImGui.ImGui_CloseCurrentPopup(RA.ctx)
    end
    ImGui.ImGui_EndDisabled(RA.ctx)
    SameLine(RA.ctx, 0, gap)
    UI.push_modal_primary_btn()
    ImGui.ImGui_BeginDisabled(RA.ctx, busy)
    local btn_label = (failed
      and font_t("common.retry", nil, "Retry")
      or font_t("common.proceed", nil, "Download")) .. "##font_download"
    if ImGui.ImGui_Button(RA.ctx, btn_label, dl_w, 0) then
      api_keys.font_download_error = nil
      local ok, reason = OptionalFonts.start_download(idx)
      if ok and reason == "ready" then
        prefs.reply_language_idx = idx
        prefs.language_code = CFG.language_code_for_legacy_idx
          and CFG.language_code_for_legacy_idx(idx) or prefs.language_code
        api_keys.pending_reply_language_idx = nil
        api_keys.missing_reply_language_font_idx = nil
        api_keys.font_prompt_force_english = nil
        if S.wrap_cache then S.wrap_cache = {} end
        ImGui.ImGui_CloseCurrentPopup(RA.ctx)
      elseif not ok then
        api_keys.font_download_error = tostring(reason
          or font_t("settings.font.start_failed", nil,
            "Font download failed to start."))
      end
    end
    ImGui.ImGui_EndDisabled(RA.ctx)
    UI.pop_modal_primary_btn()
    if ImGui.ImGui_IsKeyPressed(RA.ctx, ImGui.ImGui_Key_Escape()) and not busy then
      api_keys.pending_reply_language_idx = nil
      api_keys.font_download_error = nil
      api_keys.missing_reply_language_font_idx = idx
      api_keys.font_prompt_force_english = nil
      ImGui.ImGui_CloseCurrentPopup(RA.ctx)
    end
    ImGui.ImGui_EndPopup(RA.ctx)
  end
  UI.pop_modal_style()
end

function UI.render_language_download_status(lang_download, id_suffix)
  lang_download = type(lang_download) == "table" and lang_download or nil
  if not lang_download
      or not (lang_download.state == "index_downloading"
        or lang_download.state == "ui_downloading"
        or lang_download.state == "failed") then
    return false
  end
  local status_text = lang_download.status_text
  local status_color = TK.text_muted
  if lang_download.state == "index_downloading" then
    status_text = UI.t("settings.lang.checking", nil,
      "Checking languages...")
  elseif lang_download.state == "failed" then
    if lang_download.quiet_refresh then return false end
    status_color = TK.red
    if not status_text or status_text == "" then
      if lang_download.last_code then
        status_text = UI.t("settings.lang.failed_detail", {
          language = (LangPacks and LangPacks._display_language
            and LangPacks._display_language(lang_download.last_code)) or "",
          current = (LangPacks and LangPacks._display_language
            and LangPacks._display_language(I18N and I18N.lang_code
              and I18N.lang_code() or "en")) or "English",
          detail = lang_download.last_error or "",
        }, lang_download.last_error or "Language pack download failed.")
      else
        status_text = UI.t("settings.lang.index_failed_detail", {
          detail = lang_download.last_error or "",
        }, lang_download.last_error or "Could not check language packs.")
      end
    end
  end
  if status_text and status_text ~= "" then
    PushStyleColor(RA.ctx, ImGui.ImGui_Col_Text(), status_color)
    ImGui.ImGui_PushTextWrapPos(RA.ctx,
      GetCursorPosX(RA.ctx) + ImGui.ImGui_GetContentRegionAvail(RA.ctx))
    ImGui.ImGui_TextWrapped(RA.ctx, status_text)
    ImGui.ImGui_PopTextWrapPos(RA.ctx)
    PopStyleColor(RA.ctx)
  end
  if lang_download.state == "failed"
      and LangPacks and LangPacks.diagnostic_text then
    local copy_label = UI.t("settings.lang.copy_details", nil, "Copy details")
    local copy_w = math_max(RA.SC(96), CalcTextSize(RA.ctx, copy_label) + RA.SC(22))
    if ImGui.ImGui_Button(RA.ctx,
        copy_label .. "##lang_download_details_" .. tostring(id_suffix or ""),
        copy_w, 0) then
      ImGui.ImGui_SetClipboardText(RA.ctx,
        LangPacks.diagnostic_text(lang_download))
      if UI.show_float_toast then
        UI.show_float_toast(UI.t("settings.lang.details_copied", nil,
          "Language download details copied."), "ok")
      end
    end
  end
  return true
end

-- Destructive modal button (Run Anyway / Clear Cache / Factory Reset /
-- Confirm Clear / Confirm UI Scale down). Softened red: TK.red blended
-- ~25% toward TK.text_muted so the fill reads as serious-but-not-
-- shouting. Still clearly destructive via the red tone; desaturation
-- keeps the saturated TK.red reserved for page-level error states
-- where the extra intensity carries real warning weight.
function UI.push_modal_danger_btn()
  local danger_fill = UI.lerp_u32(TK.red, TK.text_muted, 0.25)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Button(),        danger_fill)
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonHovered(),
    UI.lerp_u32(danger_fill, 0xFFFFFFFF, 0.12))
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonActive(),
    UI.lerp_u32(danger_fill, 0x000000FF, 0.15))
  PushStyleColor(RA.ctx, ImGui.ImGui_Col_Text(),          0xFFFFFFFF)
end
function UI.pop_modal_danger_btn() PopStyleColor(RA.ctx, 4) end

-- Card-style popup (provider/model/thinking chip menus): dark card bg,
