  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FramePadding(),  RA.SC(10), RA.SC(6))
  PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_ItemSpacing(),   RA.SC(8),  RA.SC(4))
