            ImGui.ImGui_SetCursorScreenPos(RA.ctx,
              ta_sx + TA_PAD, ta_sy + TA_HEADER + TA_GAP)
            PushFont(RA.ctx, receipt_font, BODY_FONT)
            UI.selectable_text(summary, "##typed_actions_receipt_" .. i,
