              or (msg.run_status == "errored" and type(ar) == "table" and #ar > 0)
            local can_apply = type(plan_text) == "string"
              and plan_text ~= ""
              and msg.typed_actions.valid == true
              and not can_undo
              and not msg.typed_action_undo_clicked
